import Std.Math.*;
import Std.Convert.*;

operation Main() : (Int, Int) {
    // The angles for inner product. Inner product is meeasured for vectors
    // (cos(Θ₁/2), sin(Θ₁/2)) and (cos(Θ₂/2), sin(Θ₂/2)).
    let theta1 = PI() / 7.0;
    let theta2 = PI() / 5.0;
    // Number of iterations
    let n = 4;
    // Perform measurements
    Message("Computing inner product of vectors (cos(Θ₁/2), sin(Θ₁/2))⋅(cos(Θ₂/2), sin(Θ₂/2)) ≈ -cos(x𝝅/2ⁿ)");
    let result = PerformMeasurements(theta1, theta2, n);
    // Return result
    return (result, n);
}

@Config(Adaptive)
@Config(not HigherLevelConstructs)
@Config(not FloatingPointComputations)
operation PerformMeasurements(theta1 : Double, theta2 : Double, n : Int) : Int {
    let measurementCount = n + 1;
    return QuantumInnerProduct(theta1, theta2, measurementCount);
}

@Config(HigherLevelConstructs)
@Config(FloatingPointComputations)
operation PerformMeasurements(theta1 : Double, theta2 : Double, n : Int) : Int {
    Message($"Θ₁={theta1}, Θ₂={theta2}.");

    // First compute quantum approximation
    let measurementCount = n + 1;
    let x = QuantumInnerProduct(theta1, theta2, measurementCount);
    let angle = PI() * IntAsDouble(x) / IntAsDouble(2^n);
    let computedInnerProduct = -Cos(angle);
    Message($"x = {x}, n = {n}.");

    // Now compute true inner product
    let trueInnterProduct = ClassicalInnerProduct(theta1, theta2);

    Message($"Computed value = {computedInnerProduct}, true value = {trueInnterProduct}");

    return x;
}

function ClassicalInnerProduct(theta1 : Double, theta2 : Double) : Double {
    return Cos(theta1 / 2.0) * Cos(theta2 / 2.0) + Sin(theta1 / 2.0) * Sin(theta2 / 2.0);
}

operation QuantumInnerProduct(theta1 : Double, theta2 : Double, iterationCount : Int) : Int {
    //Create target register
    use TargetReg = Qubit();
    //Create ancilla register
    use AncilReg = Qubit();
    //Run iterative phase estimation
    let Results = IterativePhaseEstimation(TargetReg, AncilReg, theta1, theta2, iterationCount);
    Reset(TargetReg);
    Reset(AncilReg);
    return Results;
}

operation IterativePhaseEstimation(
    TargetReg : Qubit,
    AncilReg : Qubit,
    theta1 : Double,
    theta2 : Double,
    Measurements : Int
) : Int {

    use ControlReg = Qubit();
    mutable MeasureControlReg = [Zero, size = Measurements];
    mutable bitValue = 0;
    //Apply to initialise state, this is defined by the angles theta1 and theta2
    StateInitialisation(TargetReg, AncilReg, theta1, theta2);
    for index in 0..Measurements - 1 {
        H(ControlReg);
        //Don't apply rotation on first set of oracles
        if index > 0 {
            //Loop through previous results
            for index2 in 0..index - 1 {
                if MeasureControlReg[Measurements - 1 - index2] == One {
                    //Rotate control qubit dependent on previous measurements and number of measurements
                    let angle = -IntAsDouble(2^(index2)) * PI() / (2.0^IntAsDouble(index));
                    R(PauliZ, angle, ControlReg);
                }
            }

        }
        let powerIndex = (1 <<< (Measurements - 1 - index));
        //Apply a number of oracles equal to 2^index, where index is the number or measurements left
        for _ in 1..powerIndex {
            Controlled GOracle([ControlReg], (TargetReg, AncilReg, theta1, theta2));
        }
        H(ControlReg);
        //Make a measurement mid circuit
        set MeasureControlReg w/= (Measurements - 1 - index) <- MResetZ(ControlReg);
        if MeasureControlReg[Measurements - 1 - index] == One {
            //Assign bitValue based on previous measurement
            bitValue += 2^(index);
        }
    }
    return bitValue;
}

/// # Summary
/// This is state preparation operator A for encoding the 2D vector (page 7)
operation StateInitialisation(
    TargetReg : Qubit,
    AncilReg : Qubit,
    theta1 : Double,
    theta2 : Double
) : Unit is Adj + Ctl {

    H(AncilReg);
    // Arbitrary controlled rotation based on theta. This is vector v.
    Controlled R([AncilReg], (PauliY, theta1, TargetReg));
    // X gate on ancilla to change from |+〉 to |-〉.
    X(AncilReg);
    // Arbitrary controlled rotation based on theta. This is vector c.
    Controlled R([AncilReg], (PauliY, theta2, TargetReg));
    X(AncilReg);
    H(AncilReg);
}

operation GOracle(
    TargetReg : Qubit,
    AncilReg : Qubit,
    theta1 : Double,
    theta2 : Double
) : Unit is Adj + Ctl {

    Z(AncilReg);
    within {
        Adjoint StateInitialisation(TargetReg, AncilReg, theta1, theta2);
        X(AncilReg);
        X(TargetReg);
    } apply {
        Controlled Z([AncilReg], TargetReg);
    }
}

/// # Sample
/// Quantum Dynamics
///
/// # Description
/// This example demonstrates quantum dynamics in a style tailored for
/// resource estimation. The sample is specifically the simulation
/// of an Ising model Hamiltonian on an N1xN2 2D lattice using a
/// fourth-order Trotter Suzuki product formula, assuming
/// a 2D qubit architecture with nearest-neighbor connectivity.
/// The is an example of a program that is not amenable to simulating
/// classically, but can be run through resource estimation to determine
/// what size of quantum system would be needed to solve the problem.

import Std.Math.*;
import Std.Arrays.*;

operation Main() : Unit {
    // n : Int, m : Int, t: Double, u : Double, tstep : Double

    let n = 10;
    let m = 10;

    let J = 1.0;
    let g = 1.0;

    let totTime = 30.0;
    let dt = 0.9;

    IsingModel2DSim(n, m, J, g, totTime, dt);
}

/// # Summary
/// The function below creates a sequence containing the rotation angles that will be applied with the two operators used in the expansion of the Trotter-Suzuki formula.
/// # Input
/// ## p (Double) : Constant used for fourth-order formulas
///
/// ## dt (Double) : Time-step used to compute rotation angles
///
/// ## J (Double) : coefficient for 2-qubit interactions
///
/// ## g (Double) : coefficient for transverse field
///
/// # Output
/// ## values (Double[]) : The list of rotation angles to be applies in sequence with the corresponding operators
///
function SetAngleSequence(p : Double, dt : Double, J : Double, g : Double) : Double[] {

    let len1 = 3;
    let len2 = 3;
    let valLength = 2 * len1 + len2 + 1;
    mutable values = [0.0, size = valLength];

    let val1 = J * p * dt;
    let val2 = -g * p * dt;
    let val3 = J * (1.0 - 3.0 * p) * dt / 2.0;
    let val4 = g * (1.0 - 4.0 * p) * dt / 2.0;

    for i in 0..len1 {

        if (i % 2 == 0) {
            set values w/= i <- val1;
        } else {
            set values w/= i <- val2;
        }

    }

    for i in len1 + 1..len1 + len2 {
        if (i % 2 == 0) {
            set values w/= i <- val3;
        } else {
            set values w/= i <- val4;
        }
    }

    for i in len1 + len2 + 1..valLength - 1 {
        if (i % 2 == 0) {
            set values w/= i <- val1;
        } else {
            set values w/= i <- val2;
        }
    }
    return values;
}

/// # Summary
/// Applies e^-iX(theta) on all qubits in the 2D lattice as part of simulating the transverse field in the Ising model
/// # Input
/// ## n (Int) : Lattice size for an n x n lattice
///
/// ## qArr (Qubit[][]) : Array of qubits representing the lattice
///
/// ## theta (Double) : The angle/time-step for which the unitary simulation is done.
///
operation ApplyAllX(n : Int, qArr : Qubit[][], theta : Double) : Unit {
    // This applies `Rx` with an angle of `2.0 * theta` to all qubits in `qs`
    // using partial application
    for row in 0..n - 1 {
        ApplyToEach(Rx(2.0 * theta, _), qArr[row]);
    }
}

/// # Summary
/// Applies e^-iP(theta) where P = Z o Z as part of the repulsion terms.
/// # Input
/// ## n, m (Int, Int) : Lattice sizes for an n x m lattice
///
/// ## qArr (Qubit[]) : Array of qubits representing the lattice
///
/// ## theta (Double) : The angle/time-step for which unitary simulation is done.
///
/// ## dir (Bool) : Direction is true for vertical direction.
///
/// ## grp (Bool) : Group is true for odd starting indices
///
operation ApplyDoubleZ(n : Int, m : Int, qArr : Qubit[][], theta : Double, dir : Bool, grp : Bool) : Unit {
    let start = grp ? 1 | 0;    // Choose either odd or even indices based on group number
    let P_op = [PauliZ, PauliZ];
    let c_end = dir ? m - 1 | m - 2;
    let r_end = dir ? m - 2 | m - 1;

    for row in 0..r_end {
        for col in start..2..c_end {
            // Iterate through even or odd columns based on `grp`

            let row2 = dir ? row + 1 | row;
            let col2 = dir ? col | col + 1;

            Exp(P_op, theta, [qArr[row][col], qArr[row2][col2]]);
        }
    }
}

/// # Summary
/// The main function that takes in various parameters and calls the operations needed to simulate fourth order Trotterizatiuon of the Ising Hamiltonian for a given time-step
/// # Input
/// ## N1, N2 (Int, Int) : Lattice sizes for an N1 x N2 lattice
///
/// ## J (Double) : coefficient for 2-qubit interactions
///
/// ## g (Double) : coefficient for transverse field
///
/// ## totTime (Double) : The total time-step for which unitary simulation is done.
///
/// ## dt (Double) : The time the simulation is done for each timestep
///
operation IsingModel2DSim(N1 : Int, N2 : Int, J : Double, g : Double, totTime : Double, dt : Double) : Unit {

    use qs = Qubit[N1 * N2];
    let qubitArray = Chunks(N2, qs); // qubits are re-arranged to be in an N1 x N2 array

    let p = 1.0 / (4.0 - 4.0^(1.0 / 3.0));
    let t = Ceiling(totTime / dt);

    let seqLen = 10 * t + 1;

    let angSeq = SetAngleSequence(p, dt, J, g);

    for i in 0..seqLen - 1 {
        let theta = (i == 0 or i == seqLen - 1) ? J * p * dt / 2.0 | angSeq[i % 10];

        // for even indexes
        if i % 2 == 0 {
            ApplyAllX(N1, qubitArray, theta);
        } else {
            // iterate through all possible combinations for `dir` and `grp`.
            for (dir, grp) in [(true, true), (true, false), (false, true), (false, false)] {
                ApplyDoubleZ(N1, N2, qubitArray, theta, dir, grp);
            }
        }
    }
}

/// # Sample
/// Simplified Sample of a Variational Quantum Eigensolver
///
/// # Description
/// This is an example of a Variational Quantum Eigensolver (VQE).
/// This example includes:
///   1. Simple classical optimization to find minimum of a multi-variable function
///      in order to find an approximation to the minimum eigenvalue of a Hamiltonian
///   2. Finding Hamiltonian expectation value as a weighted sum of terms.
///   3. Finding one term expectation value by performing multiple shots.
///   4. Ansatz state preparation similar to the circuit in the referenced paper.
/// To keep this sample simple Hamiltonian terms are generated randomly.
///
/// # Reference
/// Ground-state energy estimation of the water molecule on a trapped ion quantum
/// computer by Yunseong Nam et al., 2019. https://arxiv.org/abs/1902.10171

import Std.Arrays.IsEmpty;
import Std.Arrays.IndexRange;
import Std.Convert.IntAsDouble;
import Std.Diagnostics.Fact;
import Std.Math.AbsD;
import Std.Math.PI;

/// # Summary
/// Find the approximation to the minimum eigenvalue of a Hamiltonian by applying VQE
operation Main() : Double {

    // Find the approximation to the minimum eigenvalue of a Hamiltonian
    // by varying ansatz parameters to minimize its expectation value.
    SimpleDescent(
        // Use a number of shots when estimating Hamiltonian terms
        // Actual VQE implementations may require very large number of shots.
        FindHamiltonianExpectationValue(_, 100),
        // Start from these angles for ansatz state preparation
        [1.0, 1.0],
        // Initial step to search for minimum
        0.5,
        // Stop optimization if step is 0
        0.0,
        // Stop optimization after several attempts.
        // Actual VQE would need to make enough iterations
        // to find energy with sufficient chemical accuracy.
        50
    )
}

/// # Summary
/// Find expectation value of a Hamiltonian given parameters for the
/// ansatz state and number of shots to evaluate each term.
/// Different VQE applications will have different measurements and
/// coefficients depending on the Hamiltonian being evaluated.
operation FindHamiltonianExpectationValue(thetas : Double[], shots : Int) : Double {
    let terms = [
        ([PauliZ, PauliI, PauliI, PauliI], 0.16),
        ([PauliI, PauliI, PauliZ, PauliI], -0.25),
        ([PauliZ, PauliZ, PauliI, PauliI], 0.17),
        ([PauliI, PauliI, PauliZ, PauliZ], 0.45),
        ([PauliX, PauliX, PauliX, PauliX], 0.2),
        ([PauliY, PauliY, PauliY, PauliY], 0.1),
        ([PauliY, PauliX, PauliX, PauliY], -0.02),
        ([PauliX, PauliY, PauliY, PauliX], -0.22),
    ];
    mutable value = 0.0;
    for (basis, coefficient) in terms {
        value += coefficient * FindTermExpectationValue(thetas, basis, shots);
    }
    value
}

/// # Summary
/// Find expectation value of a Hamiltonian term given parameters for the
/// ansatz state, measurement basis and number of shots to evaluate each term.
operation FindTermExpectationValue(
    thetas : Double[],
    pauliBasis : Pauli[],
    shots : Int
) : Double {

    mutable zeroCount = 0;
    for _ in 1..shots {
        use qs = Qubit[4];
        PrepareAnsatzState(qs, thetas);
        if Measure(pauliBasis, qs) == Zero {
            zeroCount += 1;
        }
        ResetAll(qs);
    }
    IntAsDouble(zeroCount) / IntAsDouble(shots)
}

/// # Summary
/// Prepare the ansatz state for given parameters on a qubit register
/// This is an example of ansatz state preparation similar to the
/// unitary couple clustered method used in the referenced paper.
/// Actual VQE application will have different ansatz preparation operations.
operation PrepareAnsatzState(qs : Qubit[], thetas : Double[]) : Unit {
    BosonicExitationTerm(thetas[0], qs[0], qs[2]);
    CNOT(qs[0], qs[1]);
    NonBosonicExitataionTerm(thetas[1], qs[0], qs[1], qs[2], qs[3]);
}

/// # Summary
/// Bosonic excitation circuit from the referenced paper.
operation BosonicExitationTerm(
    theta : Double,
    moX : Qubit,
    moY : Qubit
) : Unit {
    X(moX);
    Adjoint S(moX);
    Rxx(theta, moX, moY);
    S(moX);
    Adjoint S(moY);
    Rxx(-theta, moX, moY);
    S(moY);
}

/// # Summary
/// Non-bosonic excitation circuit from the referenced paper.
operation NonBosonicExitataionTerm(
    theta : Double,
    moXsoX : Qubit,
    moXsoY : Qubit,
    moYsoX : Qubit,
    moYsoY : Qubit
) : Unit {
    Adjoint S(moXsoX);
    within {
        CNOT(moXsoX, moYsoY);
        CNOT(moXsoX, moYsoX);
        CNOT(moXsoX, moXsoY);
        H(moXsoX);
        Rz(theta, moXsoX);
        CNOT(moXsoY, moXsoX);
        Rz(theta, moXsoX);
        CNOT(moYsoY, moXsoX);
        Rz(-theta, moXsoX);
        CNOT(moXsoY, moXsoX);
        Rz(-theta, moXsoX);
    } apply {
        Adjoint S(moYsoX);
        CNOT(moYsoX, moXsoX);
    }
    S(moYsoX);
}

/// # Summary
/// Simple classical optimizer. A descent to a local minimum of function `f`.
/// Tries to takes steps in all directions and proceeds if the new point is better.
/// If no moves result in function value improvement the step size is halved.
/// Actual VQE implementations use more elaborate optimizers.
operation SimpleDescent(
    f : Double[] => Double,
    initialPoint : Double[],
    initialStep : Double,
    minimalStep : Double,
    attemptLimit : Int
) : Double {
    Fact(not IsEmpty(initialPoint), "Argument array must contain elements.");
    Fact(initialStep > 0.0, "Initial step must be positive.");
    Fact(minimalStep >= 0.0, "Minimal step must be non-negative.");

    mutable bestPoint = initialPoint;
    mutable bestValue = f(bestPoint);
    mutable currentStep = initialStep;
    mutable currentAttempt = 0;

    Message($"Beginning descent from value {bestValue}.");

    while (currentAttempt < attemptLimit) and (currentStep > minimalStep) {
        mutable hadImprovement = false;
        for i in IndexRange(initialPoint) {
            let nextPoint = bestPoint w/ i <- bestPoint[i] + currentStep;
            let nextValue = f(nextPoint); // Evaluate quantum part
            currentAttempt = currentAttempt + 1;
            if nextValue < bestValue {
                hadImprovement = true;
                bestValue = nextValue;
                bestPoint = nextPoint;
                Message($"Value improved to {bestValue}.");
            }
            let nextPoint = bestPoint w/ i <- bestPoint[i] - currentStep;
            let nextValue = f(nextPoint); // Evaluate quantum part
            currentAttempt = currentAttempt + 1;
            if nextValue < bestValue {
                hadImprovement = true;
                bestValue = nextValue;
                bestPoint = nextPoint;
                Message($"Value improved to {bestValue}.");
            }
        }

        if not hadImprovement {
            currentStep = currentStep / 2.0;
        }
    }
    Message($"Descent done. Attempts: {currentAttempt}, Step: {currentStep}, Arguments: {bestPoint}, Value: {bestValue}.");
    bestValue
}

/// # Sample
/// Using pre-calculated logical counts for resource estimation
///
/// # Description
/// This sample demonstrates how to use the `AccountForEstimates` function to
/// estimate the resources required to run a factoring program from pre-calculated
/// logical counts. The logical counts used in this sample are the ones obtained
/// for a 2048-bit integer factoring application based on the implementation
/// described in [[Quantum 5, 433 (2021)](https://quantum-journal.org/papers/q-2021-04-15-433/)].
/// Our implementation incorporates all techniques described in the paper, except for
/// carry runways.
import Std.ResourceEstimation.*;

operation Main() : Unit {
    use qubits = Qubit[12581];

    AccountForEstimates(
        [TCount(12), RotationCount(12), RotationDepth(12), CczCount(3731607428), MeasurementCount(1078154040)],
        PSSPCLayout(),
        qubits
    );
}

// # Sample
// Custom Operations
//
// # Description
// The @Measurement attribute in Q# allows you to define custom measurements
// that are lowered to QIR in the same way the `M` measurement in the standard
// library is lowered. That means an `"irreversible"` attribute is added to
// the callable declaration and the output results are moved to the parameters
// and treated as result registers.
//
// # Who is this for?
// The target audience are library authors targeting specific hardware.

/// Try running the command `Q#: Get QIR for the current Q# program`
/// in VS-Code's Command Palette.
operation Main() : Result {
    use q = Qubit();
    H(q);
    __quantum__qis__mx__body(q)
}

@Measurement()
@SimulatableIntrinsic()
operation __quantum__qis__mx__body(q : Qubit) : Result {
    H(q);
    M(q)
}

/// # Summary
/// Greenberger–Horne–Zeilinger state sample
///
/// # Description
/// This Q# program shows how to prepare a generalized Greenberger–Horne–Zeilinger
/// state (aka Cat state) in a register of 5 qubits.
///
/// # Remarks
/// The Greenberger–Horne–Zeilinger state, or GHZ state, aka Cat state,
/// is a state defined as: |GHZ〉 = (|0...0〉 + |1...1〉)/√2.
///
/// The GHZ state is said to be a maximally entangled state, a multi-qubit
/// state where the state of any one qubit is not separable from the state
/// of any of the other qubits.
///
/// # References
/// - [Greenberger–Horne–Zeilinger state](https://en.wikipedia.org/wiki/Greenberger%E2%80%93Horne%E2%80%93Zeilinger_state)
/// - [Cat state](https://en.wikipedia.org/wiki/Cat_state)
operation Main() : Result[] {
    // Allocate 5 qubits for Cat₅ state.
    use cat5 = Qubit[5];
    // Prepare a Cat₅ state in the register.
    PrepareGHZState(cat5);
    // Show the Cat₅ state.
    Std.Diagnostics.DumpMachine();
    // Measure and reset qubits. Return results.
    MResetEachZ(cat5)
}

/// # Summary
/// Prepares GHZ state (|0...0〉 + |1...1〉) / √2 (aka Cat state) in `qs` register.
/// All qubits are assumed to be in |0〉 state on input.
operation PrepareGHZState(qs : Qubit[]) : Unit {
    Std.Diagnostics.Fact(Length(qs) > 0, "Qubit register must not be empty.");

    // Set the first qubit into a (|0〉 + |1〉) / √2 superposition.
    H(qs[0]);

    // Then apply a CNOT to the remaining qubits using the first qubit as control.
    // This entangles first qubit with all the other qubits in the register.
    for q in qs[1...] {
        CNOT(qs[0], q);
    }
}

