/// # Sample
/// Simple Quantum Phase Estimation
///
/// # Description
/// This sample demonstrates how to use ApplyQPE to perform
/// Quantum Phase Estimation of a simple unitary operation.
/// Rz gate is used as the unitary operation,
/// and the eigenvector |1⟩ is chosen for the phase estimation.
/// Run this sample and check the histogram of results.
/// This sample is suitable for base profile.

/// # Summary
/// Estimate the phase of the eigenvalue of the unitary gate U
/// using Quantum Phase Estimation (QPE) algorithm.
/// The result is returned as an array of `Result` values
/// representing the binary fraction of the phase in big-endian order.
/// This is used to display the histogram of the results.
operation Main() : Result[] {
    // Allocate qubits to be used in phase estimation
    use state = Qubit();
    use phase = Qubit[6];

    // Prepare Rz eigenvector |1⟩
    X(state);

    // ApplyOperationPowerCA is used to apply the unitary operation U multiple times
    // as required by the Quantum Phase Estimation algorithm. In general, unitary U may
    // operate on multiple qubits, but in this case it operates on a single qubit qs[0].
    let oracle = ApplyOperationPowerCA(_, qs => U(qs[0]), _);

    // Estimate eigenvalue of Rz gate corresponding eigenvector |1⟩
    // In general, unitary U may operate on multiple qubits, but in this case
    // it operates on a single qubit state. So a single element array [state] is passed
    // as the target state.
    ApplyQPE(oracle, [state], phase);

    // Measure each qubit in the phase register
    let results = MeasureEachZ(phase);

    // Reset the qubits
    Reset(state);
    ResetAll(phase);

    // For the gate Rz(π/3) and the eigenvector |1⟩, the eigenvalue should be exp(i * π/6).
    // Its phase π/6 is 1/12 as a frction of 2π, or ~0.0001010101 in binary.
    // Estimation is done with the precision of 6 binary digits so the expected histogram
    // should peak at [Zero, Zero, Zero, One, Zero, One] (big-endian order),
    // with the smaller bar at the next value [Zero, Zero, Zero, One, One, Zero]

    // Reverse the order of the results to present in big-endian
    // and return one data point for histogram display
    Std.Arrays.Reversed(results)
}

// U is the unitary gate for which we want to perform phase estimation.
operation U(q : Qubit) : Unit is Ctl + Adj {
    // Using the Rz gate with the angle of π/3
    // The eigenvalues of this gate are exp(-i * π/6) for |0⟩ and exp(i * π/6) for |1⟩.
    Rz(Std.Math.PI() / 3.0, q);
}

// # Sample
// Class Constraints
//
// # Description
// Q# supports constraining generic types via _class constraints_. The formal term for this concept is bounded polymorphism,
// or parametric polymorphism.

// A generic type, or type parameter, is specified on a callable declaration to signify that a function can take multiple types of data as input.
// For a generic type parameter to be useful, we need to be able to know enough about it to operate on it. This is where class constraints come in. By specifying
// class constraints for a type parameter, we are limiting what types can be passed as arguments to a subset with known properties.

// Classes that Q# currently supports are:
// - `Eq`: denotes that a type can be compared to other values of the same type via the `==` operator.
// - `Add`: denotes that a type can be added to other values of the same type via the `+` operator.
// - `Mul`: denotes that a type can be used with the multiplication (`*`) operator.
// - `Mod`: denotes that a type can be used with the modulo (`%`) operator.
// - `Sub`: denotes that a type can subtracted from other values of the same type via the  `-` operator.
// - `Div`: denotes that a type can subtracted from other values of the same type via the  `/` operator.
// - `Signed`: denotes that a type can be negated or made positive with `+` or `-` unary operator prefixes.
// - `Ord`: denotes that a type can be used with comparison operators (`>`, `<`, `>=`, `<=`).
// - `Show`: denotes that a type can be converted to a string via format strings (`$"number: {num}"`).
// - `Exp['T]`: denotes that a type can be raised to a power of type `'T`. The return type of exponentiation is the type of the base.
// - `Integral`: denotes that a type is an integer-ish type, i.e., can be used in following expressions using the following operators: `&&&`, `|||`, `^^^`, `<<<`, and `>>>`.

// For example, we may want to write a function that checks if a list is full of entirely the same item. `f([3, 3, 3])` would be `true` and `f([3, 4])` would be false.
function AllEqual<'T : Eq>(items : 'T[]) : Bool {
    let allEqual = true;
    for i in 1..Length(items) - 1 {
        if items[i] != items[i - 1] {
            return false;
        }
    }
    return true;
}

function Main() : Unit {
    let is_equal = AllEqual([1, 1, 1]);
    Message($"{is_equal}");

    let is_equal = AllEqual([1, 2, 3]);
    Message($"{is_equal}");

    // Because we wrote this function generically, we are able to pass in different types, as
    // long as they can be compared via the class `Eq`.
    let is_equal = AllEqual([true, true, false]);
    Message($"{is_equal}");

    let is_equal = AllEqual(["a", "b"]);
    Message($"{is_equal}");

    let is_equal = AllEqual([[], [1]]);
    Message($"{is_equal}");

    let is_equal = AllEqual([[1], [1]]);
    Message($"{is_equal}");
}

/// # Sample
/// Quantum Teleportation
///
/// # Description
/// Quantum teleportation provides a way of moving a quantum state from one
/// location to another without having to move physical particle(s) along with
/// it. This is done with the help of previously shared quantum entanglement
/// between the sending and the receiving locations, and classical
/// communication.
///
/// This Q# program implements quantum teleportation.
import Std.Diagnostics.*;
import Std.Intrinsic.*;
import Std.Measurement.*;


operation Main() : Result[] {
    // Use the `Teleport` operation to send different quantum states.
    let stateInitializerBasisTuples = [
        ("|0〉", I, PauliZ),
        ("|1〉", X, PauliZ),
        ("|+〉", SetToPlus, PauliX),
        ("|-〉", SetToMinus, PauliX)
    ];

    mutable results = [];
    for (state, initializer, basis) in stateInitializerBasisTuples {
        // Allocate the message and target qubits.
        use (message, target) = (Qubit(), Qubit());

        // Initialize the message and show its state using the `DumpMachine`
        // function.
        initializer(message);
        Message($"Teleporting state {state}");
        DumpRegister([message]);

        // Teleport the message and show the quantum state after
        // teleportation.
        Teleport(message, target);
        Message($"Received state {state}");
        DumpRegister([target]);

        // Measure target in the corresponding basis and reset the qubits to
        // continue teleporting more messages.
        let result = Measure([basis], [target]);
        results += [result];
        ResetAll([message, target]);
    }

    return results;
}

/// # Summary
/// Sends the state of one qubit to a target qubit by using teleportation.
///
/// Notice that after calling Teleport, the state of `message` is collapsed.
///
/// # Input
/// ## message
/// A qubit whose state we wish to send.
/// ## target
/// A qubit initially in the |0〉 state that we want to send
/// the state of message to.
operation Teleport(message : Qubit, target : Qubit) : Unit {
    // Allocate an auxiliary qubit.
    use auxiliary = Qubit();

    // Create some entanglement that we can use to send our message.
    H(auxiliary);
    CNOT(auxiliary, target);

    // Encode the message into the entangled pair.
    CNOT(message, auxiliary);
    H(message);

    // Measure the qubits to extract the classical data we need to decode
    // the message by applying the corrections on the target qubit
    // accordingly.
    if M(auxiliary) == One {
        X(target);
    }

    if M(message) == One {
        Z(target);
    }

    // Reset auxiliary qubit before releasing.
    Reset(auxiliary);
}

/// # Summary
/// Sets a qubit in state |0⟩ to |+⟩.
operation SetToPlus(q : Qubit) : Unit is Adj + Ctl {
    H(q);
}

/// # Summary
/// Sets a qubit in state |0⟩ to |−⟩.
operation SetToMinus(q : Qubit) : Unit is Adj + Ctl {
    X(q);
    H(q);
}

/// # Sample
/// Hidden Shift
///
/// # Description
/// There is a family of problems known as hidden shift problems, in which it
/// is given that two Boolean functions 𝑓 and 𝑔 satisfy the relation
///     𝑔(𝑥) = 𝑓(𝑥 ⊕ 𝑠) for all 𝑥
/// where 𝑠 is a hidden bit string that we would like to find.
///
/// This Q# program implements an algorithm to solve the hidden shift problem.
import Std.Arrays.*;
import Std.Convert.*;
import Std.Diagnostics.*;
import Std.Measurement.*;

operation Main() : Int[] {
    let nQubits = 10;

    // Consider the case of finding a hidden shift 𝑠 between two Boolean
    // functions 𝑓(𝑥) and 𝑔(𝑥) = 𝑓(𝑥 ⊕ 𝑠).
    // This problem can be solved on a quantum computer with one call to
    // each of 𝑓 and 𝑔 in the special case that both functions are bent;
    // that is, that they are as far from linear as possible.

    // Here, we find the hidden shift for various pairs of bent functions.
    let shifts = [170, 512, 999];
    mutable hiddenShifts = [];
    for shift in shifts {
        let hiddenShiftBitString = FindHiddenShift(
            BentFunction,
            register => ShiftedBentFunction(shift, register),
            nQubits
        );
        let hiddenShift = ResultArrayAsInt(hiddenShiftBitString);
        Message($"Found {shift} successfully!");
        hiddenShifts += [hiddenShift];
    }

    // Note: returned array should match shifts array
    return hiddenShifts;
}

/// # Summary
/// Implements a correlation-based algorithm to solve the hidden shift
/// problem for bent functions.
///
/// # Description
/// Implements a solution for the hidden shift problem, which is to identify
/// an unknown shift 𝑠 of the arguments of two Boolean functions 𝑓 and 𝑔
/// that are promised to satisfy the relation 𝑔(𝑥) = 𝑓(𝑥 ⊕ 𝑠) for all 𝑥.
///
/// 𝑓 and 𝑔 are assumed to be bent functions. A Boolean function is bent if
/// it is as far from linear as possible. In particular, bent functions have
/// flat Fourier (Walsh–Hadamard) spectra.
///
/// In this case, the Roetteler algorithm (see References, below) uses
/// black-box oracles for 𝑓^* and 𝑔, where 𝑓^* is the dual bent function to
/// 𝑓, and computes the hidden shift 𝑠 between 𝑓 and 𝑔.
///
/// # Input
/// ## Ufstar
/// A quantum operation that implements
/// $U_f^*: |𝑥〉 ↦ (-1)^{f^*(x)} |𝑥〉$,
/// where $f^*$ is a Boolean function, 𝑥 is an $n$ bit register
/// ## Ug
/// A quantum operation that implements
/// $U_g:|𝑥〉 ↦ (-1)^{g(x)} |𝑥〉$,
/// where 𝑔 is a Boolean function that is shifted by unknown
/// 𝑠 from 𝑓, and 𝑥 is an $n$ bit register.
/// ## n
/// The number of bits of the input register |𝑥〉.
///
/// # Output
/// An array of type `Result[]` which encodes the bit representation
/// of the hidden shift.
///
/// # References
/// - [*Martin Roetteler*,
///    Proc. SODA 2010, ACM, pp. 448-457, 2010]
///   (https://doi.org/10.1137/1.9781611973075.37)
operation FindHiddenShift(
    Ufstar : (Qubit[] => Unit),
    Ug : (Qubit[] => Unit),
    n : Int
) : Result[] {
    // We allocate n clean qubits. Note that the function Ufstar and Ug are
    // unitary operations on n qubits defined via phase encoding.
    use qubits = Qubit[n];

    // First, a Hadamard transform is applied to each of the qubits.
    ApplyToEach(H, qubits);

    // We now apply the shifted function Ug to the n qubits, computing
    // |x〉 -> (-1)^{g(x)} |x〉.
    Ug(qubits);

    within {
        // A Hadamard transform is applied to each of the n qubits.
        ApplyToEachA(H, qubits);
    } apply {
        // we now apply the dual function of the unshifted function, i.e.,
        // Ufstar, to the n qubits, computing |x〉 -> (-1)^{fstar(x)} |x〉.
        Ufstar(qubits);
    }

    // Measure the n qubits and reset them to zero so that they can be
    // safely deallocated at the end of the block.
    return MResetEachZ(qubits);
}

/// # Summary
/// Implements an oracle for a bent function constructed from the inner
/// product of Boolean functions.
///
/// # Description
/// This operation defines the Boolean function IP(x_0, ..., x_{n-1}) which
/// is computed into the phase, i.e., a diagonal operator that maps
/// |x〉 -> (-1)^{IP(x)} |x〉, where x stands for x=(x_0, ..., x_{n-1}) and all
/// the x_i are binary. The IP function is defined as
/// IP(y, z) = y_0 z_0 + y_1 z_1 + ... y_{u-1} z_{u-1} where
/// y = (y_0, ..., y_{u-1}) and z =  (z_0, ..., z_{u-1}) are two bit vectors
/// of length u. Notice that the function IP is a Boolean function on n = 2u
/// bits. IP is a special case of bent function. These are functions for
/// which the Walsh-Hadamard transform is perfectly flat (in absolute
/// value).
/// Because of this flatness, the Walsh-Hadamard spectrum of any bent
/// function defines a +1/-1 function, i.e., gives rise to another Boolean
/// function, called the dual bent function. Moreover, for the case of the
/// IP function it can be shown that IP is equal to its own dual bent
/// function.
///
/// # Remarks
/// Notice that a diagonal operator implementing IP between 2 variables y_0
/// and z_0 is nothing but the AND function between those variables, i.e.,
/// in phase encoding it is computed by a Controlled-Z gate.
/// Extending this to an XOR of the AND of more variables, as required in
/// the definition of the IP function can then be accomplished by applying
/// several Controlled-Z gates between the respective inputs.
operation BentFunction(register : Qubit[]) : Unit {
    Fact(Length(register) % 2 == 0, "Length of register must be even.");
    let u = Length(register) / 2;
    let xs = register[0..u - 1];
    let ys = register[u...];
    for index in 0..u - 1 {
        CZ(xs[index], ys[index]);
    }
}

/// # Summary
/// Implements a shifted bend function 𝑔(𝑥) = 𝑓(𝑥 ⊕ 𝑠).
///
/// # Description
/// For the hidden shift problem we need another function g which is related
/// to IP via g(x) = IP(x + s), i.e., we have to shift the argument of the
/// IP function by a given shift. Notice that the '+' operation here is the
/// Boolean addition, i.e., a bit-wise operation. Notice further, that in
/// general a diagonal operation |x〉 -> (-1)^{f(x)} can be turned into a
/// shifted version by applying a bit flip to the |x〉 register first, then
/// applying the diagonal operation, and then undoing the bit flips to the
/// |x〉 register. We use this principle to define shifted versions of the IP
/// operation.
operation ShiftedBentFunction(shift : Int, register : Qubit[]) : Unit {
    Fact(Length(register) % 2 == 0, "Length of register must be even.");
    let u = Length(register) / 2;
    within {
        // Flips the bits in shift.
        ApplyXorInPlace(shift, register);
    } apply {
        // Compute the IP function into the phase.
        BentFunction(register);
    }
}

/// # Summary
/// Bell States sample
///
/// # Description
/// This Q# sample shows how to prepare the four different Bell states.
///
/// # Remarks
/// Bell states or EPR pairs are specific quantum states of two qubits
/// that represent the simplest (and maximal) examples of quantum entanglement.
///
/// # References
/// - [Bell state](https://en.wikipedia.org/wiki/Bell_state)
operation Main() : (Result, Result)[] {
    // Prepare and measure each pair. Return an array of these results.
    [
        PrepareAndMeasurePair(PreparePhiPlus, "|Φ+〉"),
        PrepareAndMeasurePair(PreparePhiMinus, "|Φ-〉"),
        PrepareAndMeasurePair(PreparePsiPlus, "|Ψ+〉"),
        PrepareAndMeasurePair(PreparePsiMinus, "|Ψ-〉")
    ]
}

/// # Summary
/// Allocates a pair of qubits, prepares them using `preparation` operation,
/// Then measures and resets them. Returns a pair of results.
operation PrepareAndMeasurePair(
    preparation : Qubit[] => Unit,
    name : String
) : (Result, Result) {
    // Allocate a pair of qubits
    use pair = Qubit[2];
    // Prepare them using the preparation operation
    preparation(pair);
    // Show the name of the prepared state
    Message($"Bell state {name}:");
    // Show the prepared state
    Std.Diagnostics.DumpMachine();
    // Measure, reset and return
    (MResetZ(pair[0]), MResetZ(pair[1]))
}

/// # Summary
/// Prepares |Φ+⟩ = (|00⟩+|11⟩)/√2 state assuming `register` is in |00⟩ state.
operation PreparePhiPlus(register : Qubit[]) : Unit {
    H(register[0]);                 // |+0〉
    CNOT(register[0], register[1]); // (|00〉 + |11〉)/sqrt(2)
}

/// # Summary
/// Prepares |Φ−⟩ = (|00⟩-|11⟩)/√2 state assuming `register` is in |00⟩ state.
operation PreparePhiMinus(register : Qubit[]) : Unit {
    H(register[0]);                 // |+0〉
    Z(register[0]);                 // |-0〉
    CNOT(register[0], register[1]); // (|00〉 - |11〉)/sqrt(2)
}

/// # Summary
/// Prepares |Ψ+⟩ = (|01⟩+|10⟩)/√2 state assuming `register` is in |00⟩ state.
operation PreparePsiPlus(register : Qubit[]) : Unit {
    H(register[0]);                 // |+0〉
    X(register[1]);                 // |+1〉
    CNOT(register[0], register[1]); // (|01〉 + |10〉)/sqrt(2)
}

/// # Summary
/// Prepares |Ψ−⟩ = (|01⟩-|10⟩)/√2 state assuming `register` is in |00⟩ state.
operation PreparePsiMinus(register : Qubit[]) : Unit {
    H(register[0]);                 // |+0〉
    Z(register[0]);                 // |-0〉
    X(register[1]);                 // |-1〉
    CNOT(register[0], register[1]); // (|01〉 - |10〉)/sqrt(2)
}

/// # Sample
/// Estimating Frequency for Shor's algorithm
///
/// # Description
/// In this sample we concentrate on costing the `EstimateFrequency`
/// operation, which is the core quantum operation in Shor's algorithm, and
/// we omit the classical pre- and post-processing. This makes it ideal for
/// use with the Microsoft Quantum Resource Estimator.
import Std.Arrays.*;
import Std.Canon.*;
import Std.Convert.*;
import Std.Diagnostics.*;
import Std.Intrinsic.*;
import Std.Math.*;
import Std.Measurement.*;
import Std.Arithmetic.*;
import Std.ResourceEstimation.*;

operation Main() : Unit {
    let bitsize = 31;

    // When chooseing parameters for `EstimateFrequency`, make sure that
    // generator and modules are not co-prime
    let _ = EstimateFrequency(11, 2^bitsize - 1, bitsize);
}

/// # Summary
/// Estimates the frequency of a generator
/// in the residue ring Z mod `modulus`.
///
/// # Input
/// ## generator
/// The unsigned integer multiplicative order (period)
/// of which is being estimated. Must be co-prime to `modulus`.
/// ## modulus
/// The modulus which defines the residue ring Z mod `modulus`
/// in which the multiplicative order of `generator` is being estimated.
/// ## bitsize
/// Number of bits needed to represent the modulus.
///
/// # Output
/// The numerator k of dyadic fraction k/2^bitsPrecision
/// approximating s/r.
operation EstimateFrequency(
    generator : Int,
    modulus : Int,
    bitsize : Int
) : Int {
    mutable frequencyEstimate = 0;
    let bitsPrecision = 2 * bitsize + 1;

    // Allocate qubits for the superposition of eigenstates of
    // the oracle that is used in period finding.
    use eigenstateRegister = Qubit[bitsize];

    // Initialize eigenstateRegister to 1, which is a superposition of
    // the eigenstates we are estimating the phases of.
    // We first interpret the register as encoding an unsigned integer
    // in little endian encoding.
    ApplyXorInPlace(1, eigenstateRegister);
    let oracle = ApplyOrderFindingOracle(generator, modulus, _, _);

    // Use phase estimation with a semiclassical Fourier transform to
    // estimate the frequency.
    use c = Qubit();
    for idx in bitsPrecision - 1..-1..0 {
        within {
            H(c);
        } apply {
            // `BeginEstimateCaching` and `EndEstimateCaching` are the operations
            // exposed by Microsoft Quantum Resource Estimator. These will instruct
            // resource counting such that the if-block will be executed
            // only once, its resources will be cached, and appended in
            // every other iteration.
            if BeginEstimateCaching("ControlledOracle", SingleVariant()) {
                Controlled oracle([c], (1 <<< idx, eigenstateRegister));
                EndEstimateCaching();
            }
            R1Frac(frequencyEstimate, bitsPrecision - 1 - idx, c);
        }
        if MResetZ(c) == One {
            frequencyEstimate += 1 <<< (bitsPrecision - 1 - idx);
        }
    }

    // Return all the qubits used for oracle's eigenstate back to 0 state
    // using Std.Intrinsic.ResetAll.
    ResetAll(eigenstateRegister);

    return frequencyEstimate;
}

/// # Summary
/// Interprets `target` as encoding unsigned little-endian integer k
/// and performs transformation |k⟩ ↦ |gᵖ⋅k mod N ⟩ where
/// p is `power`, g is `generator` and N is `modulus`.
///
/// # Input
/// ## generator
/// The unsigned integer multiplicative order (period)
/// of which is being estimated. Must be co-prime to `modulus`.
/// ## modulus
/// The modulus which defines the residue ring Z mod `modulus`
/// in which the multiplicative order of `generator` is being estimated.
/// ## power
/// Power of `generator` by which `target` is multiplied.
/// ## target
/// Register interpreted as little-endian which is multiplied by
/// given power of the generator. The multiplication is performed modulo
/// `modulus`.
internal operation ApplyOrderFindingOracle(
    generator : Int,
    modulus : Int,
    power : Int,
    target : Qubit[]
) : Unit is Adj + Ctl {
    // The oracle we use for order finding implements |x⟩ ↦ |x⋅a mod N⟩. We
    // also use `ExpModI` to compute a by which x must be multiplied. Also
    // note that we interpret target as unsigned integer in little-endian
    // format.
    ModularMultiplyByConstant(
        modulus,
        ExpModI(generator, power, modulus),
        target
    );
}

/// # Summary
/// Performs modular in-place multiplication by a classical constant.
///
/// # Description
/// Given the classical constants `c` and `modulus`, and an input quantum
/// register |𝑦⟩ in little-endian format, this operation computes
/// `(c*x) % modulus` into |𝑦⟩.
///
/// # Input
/// ## modulus
/// Modulus to use for modular multiplication
/// ## c
/// Constant by which to multiply |𝑦⟩
/// ## y
/// Quantum register of target
internal operation ModularMultiplyByConstant(modulus : Int, c : Int, y : Qubit[]) : Unit is Adj + Ctl {
    use qs = Qubit[Length(y)];
    for idx in IndexRange(y) {
        let shiftedC = (c <<< idx) % modulus;
        Controlled ModularAddConstant(
            [y[idx]],
            (modulus, shiftedC, qs)
        );
    }
    for idx in IndexRange(y) {
        SWAP(y[idx], qs[idx]);
    }
    let invC = InverseModI(c, modulus);
    for idx in IndexRange(y) {
        let shiftedC = (invC <<< idx) % modulus;
        Controlled ModularAddConstant(
            [y[idx]],
            (modulus, modulus - shiftedC, qs)
        );
    }
}

/// # Summary
/// Performs modular in-place addition of a classical constant into a
/// quantum register.
///
/// Given the classical constants `c` and `modulus`, and an input quantum
/// register |𝑦⟩ in little-endian format, this operation computes
/// `(x+c) % modulus` into |𝑦⟩.
///
/// # Input
/// ## modulus
/// Modulus to use for modular addition
/// ## c
/// Constant to add to |𝑦⟩
/// ## y
/// Quantum register of target
internal operation ModularAddConstant(modulus : Int, c : Int, y : Qubit[]) : Unit is Adj + Ctl {
    body (...) {
        Controlled ModularAddConstant([], (modulus, c, y));
    }
    controlled (ctrls, ...) {
        // We apply a custom strategy to control this operation instead of
        // letting the compiler create the controlled variant for us in
        // which the `Controlled` functor would be distributed over each
        // operation in the body.
        //
        // Here we can use some scratch memory to save ensure that at most
        // one control qubit is used for costly operations such as
        // `AddConstant` and `CompareGreaterThenOrEqualConstant`.
        if Length(ctrls) >= 2 {
            use control = Qubit();
            within {
                Controlled X(ctrls, control);
            } apply {
                Controlled ModularAddConstant([control], (modulus, c, y));
            }
        } else {
            use carry = Qubit();
            Controlled IncByI(ctrls, (c, y + [carry]));
            Controlled Adjoint IncByI(ctrls, (modulus, y + [carry]));
            Controlled IncByI([carry], (modulus, y));
            Controlled ApplyIfLessOrEqualL(ctrls, (X, IntAsBigInt(c), y, carry));
        }
    }
}

/// # Sample
/// Deutsch–Jozsa Algorithm
///
/// # Description
/// Deutsch–Jozsa is a quantum algorithm that determines whether a given Boolean
/// function 𝑓 is constant (0 on all inputs or 1 on all inputs) or balanced
/// (1 for exactly half of the input domain and 0 for the other half).
///
/// This Q# program implements the Deutsch–Jozsa algorithm.
import Std.Diagnostics.*;
import Std.Math.*;
import Std.Measurement.*;

operation Main() : (String, Bool)[] {
    // A Boolean function is a function that maps bitstrings to a bit:
    //     𝑓 : {0, 1}^n → {0, 1}.

    // We say that 𝑓 is constant if 𝑓(𝑥⃗) = 𝑓(𝑦⃗) for all bitstrings 𝑥⃗ and
    // 𝑦⃗, and that 𝑓 is balanced if 𝑓 evaluates to true for exactly half of
    // its inputs.

    // If we are given a function 𝑓 as a quantum operation 𝑈 |𝑥〉|𝑦〉 =
    // |𝑥〉|𝑦 ⊕ 𝑓(𝑥)〉, and are promised that 𝑓 is either constant or is
    // balanced, then the Deutsch–Jozsa algorithm decides between these
    // cases with a single application of 𝑈.

    // Here, we demonstrate the use of the Deutsch-Jozsa algorithm by
    // determining the type (constant or balanced) of various functions.
    let nameFunctionTypeTuples = [
        ("SimpleConstantBoolF", SimpleConstantBoolF, true),
        ("SimpleBalancedBoolF", SimpleBalancedBoolF, false),
        ("ConstantBoolF", ConstantBoolF, true),
        ("BalancedBoolF", BalancedBoolF, false)
    ];

    mutable results = [];
    for (name, fn, shouldBeConstant) in nameFunctionTypeTuples {
        let isConstant = DeutschJozsa(fn, 5);
        if (isConstant != shouldBeConstant) {
            let shouldBeConstantStr = shouldBeConstant ? "constant" | "balanced";
            fail $"{name} should be detected as {shouldBeConstantStr}";
        }

        let isConstantStr = isConstant ? "constant" | "balanced";
        Message($"{name} is {isConstantStr}");
        results += [(name, isConstant)];
    }

    return results;
}

/// # Summary
/// This operation implements the DeutschJozsa algorithm.
/// It returns the Boolean value `true` if the function is constant and
/// `false` if it is not.
/// It is assumed that the function is either constant or balanced.
///
/// # Input
/// ## Uf
/// A quantum operation that implements |𝑥〉|𝑦〉 ↦ |𝑥〉|𝑦 ⊕ 𝑓(𝑥)〉, where 𝑓 is a
/// Boolean function, 𝑥 is an 𝑛 bit register and 𝑦 is a single qubit.
/// ## n
/// The number of bits in the input register |𝑥〉.
///
/// # Output
/// A boolean value `true` that indicates that the function is constant and
/// `false` that indicates that the function is balanced.
///
/// # See Also
/// - For details see Section 1.4.3 of Nielsen & Chuang.
///
/// # References
/// - [ *Michael A. Nielsen , Isaac L. Chuang*,
///     Quantum Computation and Quantum Information ]
/// (http://doi.org/10.1017/CBO9780511976667)
operation DeutschJozsa(Uf : ((Qubit[], Qubit) => Unit), n : Int) : Bool {
    // We allocate n + 1 clean qubits. Note that the function `Uf` is defined
    // on inputs of the form (x, y), where x has n bits and y has 1 bit.
    use queryRegister = Qubit[n];
    use target = Qubit();

    // The last qubit needs to be flipped so that the function will actually
    // be computed into the phase when Uf is applied.
    X(target);

    // Now, a Hadamard transform is applied to each of the qubits.
    H(target);
    // We use a within-apply block to ensure that the Hadamard transform is
    // correctly inverted on the |𝑥〉 register.
    within {
        for q in queryRegister {
            H(q);
        }
    } apply {
        // We apply Uf to the n+1 qubits, computing |𝑥, 𝑦〉 ↦ |𝑥, 𝑦 ⊕ 𝑓(𝑥)〉.
        Uf(queryRegister, target);
    }

    // The following for-loop measures all qubits and resets them to the |0〉
    // state so that they can be safely deallocated at the end of the block.
    // The loop also sets `result` to `true` if all measurement results are
    // `Zero`, i.e. if the function is a constant function, and sets
    // `result` to `false` if not, which according to the assumption on 𝑓
    // means that it must be balanced.
    mutable result = true;
    for q in queryRegister {
        if MResetZ(q) == One {
            result = false;
        }
    }

    // Finally, the last qubit, which held the 𝑦-register, is reset.
    Reset(target);
    return result;
}

// Simple constant Boolean function
operation SimpleConstantBoolF(args : Qubit[], target : Qubit) : Unit {
    X(target);
}

// Simple balanced Boolean function
operation SimpleBalancedBoolF(args : Qubit[], target : Qubit) : Unit {
    CX(args[0], target);
}

// A more complex constant Boolean function.
// It applies X to every input basis vector.
operation ConstantBoolF(args : Qubit[], target : Qubit) : Unit {
    for i in 0..(2^Length(args)) - 1 {
        ApplyControlledOnInt(i, X, args, target);
    }
}

// A more complex balanced Boolean function.
// It applies X to half of the input basis vectors.
operation BalancedBoolF(args : Qubit[], target : Qubit) : Unit {
    for i in 0..2..(2^Length(args)) - 1 {
        ApplyControlledOnInt(i, X, args, target);
    }
}

/// # Summary
/// Bell Pair sample
///
/// # Description
/// Bell pairs are specific quantum states of two qubits that represent
/// the simplest (and maximal) examples of quantum entanglement. This sample
/// prepares |Φ⁺⟩ = (|00⟩+|11⟩)/√2. For other Bell states see BellStates.qs
///
/// # References
/// - [Bell state](https://en.wikipedia.org/wiki/Bell_state)
operation Main() : (Result, Result) {
    // Allocate the two qubits that will be used to create a Bell pair.
    use (q1, q2) = (Qubit(), Qubit());

    // Create Bell pair by calling `PrepareBellPair` operation defined below.
    PrepareBellPair(q1, q2);

    // Show the state of qubits using the `DumpMachine` function.
    Std.Diagnostics.DumpMachine();

    // Measure the two qubits and reset them. Return measurement results.
    (MResetZ(q1), MResetZ(q2))
}

/// # Summary
/// Prepare Bell pair |Φ⁺⟩ = (|00⟩+|11⟩)/√2 on two qubits.
/// Qubits are assumed to be in |00⟩ state.
operation PrepareBellPair(q1 : Qubit, q2 : Qubit) : Unit {
    // Set qubit `q1` in superposition of |0⟩ and |1⟩ by applying a Hadamard gate.
    H(q1);

    // Entangle the two qubits `q1` and `q2` using the `CNOT` gate.
    CNOT(q1, q2);
}

/// # Sample
/// Simulation of a simple Ising model evolution
/// on a 1D grid with first-order Trotterization.
///
/// # Description
/// This sample demonstrates simulation of an Ising model Hamiltonian
/// on 1D grid of size N using a first-order Trotter-Suzuki approximation.
/// This sample can be easily simulated classically with the grid of size 9
/// and 1000 shots. This sample is suitable for Base Profile.
/// For the purpose of simplicity this sample intentionally doesn't
/// post-process results or perform eigenvalue estimation.
operation Main() : Result[] {
    // The size of a 1D grid is N
    let N : Int = 9;

    // Total evolution time
    let evolutionTime : Double = 4.0;
    // Number of steps
    let numberOfSteps : Int = 7;

    // Coefficient for 2-qubit interactions between neighboring qubits
    let J : Double = 1.0;
    // Coefficient for external field interaction for individual qubits
    let g : Double = 0.7;

    IsingModel1DEvolution(N, J, g, evolutionTime, numberOfSteps)
}

/// # Summary
/// Simulate simple Ising model evolution
///
/// # Description
/// Simulates state |𝜓⟩ evolution to find |𝜓(t)⟩=U(t)|𝜓(0)⟩.
/// |𝜓(0)⟩ is taken to be |0...0⟩.
/// U(t)=e⁻ⁱᴴᵗ, where H is an Ising model Hamiltonian H = -J·Σ'ᵢⱼZᵢZⱼ + g·ΣᵢXᵢ
/// Here Σ' is taken over all pairs of neighboring qubits <i,j>.
/// Simulation is done by performing K steps assuming U(t)≈(U(t/K))ᴷ.
operation IsingModel1DEvolution(
    N : Int,
    J : Double,
    g : Double,
    evolutionTime : Double,
    numberOfSteps : Int
) : Result[] {

    // Allocate qubit grid
    use qubits = Qubit[N];

    // Compute the time step
    let dt : Double = evolutionTime / Std.Convert.IntAsDouble(numberOfSteps);

    let theta_x = - g * dt;
    let theta_zz = J * dt;

    // Perform K steps
    for i in 1..numberOfSteps {

        // Single-qubit interaction with external field
        for q in qubits {
            Rx(2.0 * theta_x, q);
        }

        // All of the following Rzz gates commute. So we apply them between "even"
        // pairs first and then between "odd" pairs to reduce the algorithm depth.

        // Interactions between "even" pairs
        for j in 0..2..N-2 {
            Rzz(2.0 * theta_zz, qubits[j], qubits[j + 1]);
        }

        // Interactions between "odd" pairs
        for j in 1..2..N-2 {
            Rzz(2.0 * theta_zz, qubits[j], qubits[j + 1]);
        }

    }

    MResetEachZ(qubits)
}

/// # Summary
/// Measurement sample
///
/// # Description
/// This Q# program demonstrates how to perform measurements in Z basis.
///
/// # Remarks
/// Quantum measurement is an irreversible operation in which a quantum system
/// is manipulated to yield a numerical result. Measuring a quantum system
/// generally changes the quantum state that describes that system.
operation Main() : (Result, Result[]) {
    // Allocate a qubit. Qubit is in |0〉 state after allocation.
    use q = Qubit();
    // Flip the state. Qubit is in |1〉 state now.
    X(q);

    // The `MResetZ` operation performs a measurement of a single qubit in the
    // computational basis, also known as the Pauli Z basis. Then it resets
    // the qubit to |0〉 state. `MResetZ` may be more efficient than measuring
    // a qubit and resetting it using two separate operations.
    let result = MResetZ(q);

    // Allocate a two-qubit array (or register).
    use qs = Qubit[2];

    // The `MResetEachZ` operation measures each qubit in an array in the
    // computational basis and resets each qubit to |0〉 state. It returns
    // an array of `Result` values.
    let results = MResetEachZ(qs);

    // Return all results. In Q#, the result of a measurement is a value
    // of the type `Result`, that is, `One` or `Zero`.
    (result, results)
}

