// # Sample
// Specializations
//
// # Description
// Q# allows specialized implementations. Operations in Q# can implicitly
// or explicitly define adjoint and/or controlled versions.
// Q# employs symbolic computation that can automatically generate the
// corresponding adjoint and controlled implementations for a particular
// body implementation.

/// The adjoint, controlled and adjoint-controlled specializations are implicitly
/// generated for the `DoNothing` operation that declares supports for these
/// specializations using the `is` keyword followed by the union of the supported
/// specializations (`Adj + Ctl`).
operation DoNothing() : Unit is Adj + Ctl {}

/// Here, the specializations have been explicitly defined.
/// In the following example, the declaration for an operation SWAP,
/// which exchanges the state of two qubits q1 and q2, declares an
/// explicit specialization for its adjoint version and its controlled
/// version. While the implementations for Adjoint SWAP and Controlled
/// SWAP are thus user-defined, the compiler still needs to generate
/// the implementation for the combination of both functors (Controlled
/// Adjoint SWAP, which is the same as Adjoint Controlled SWAP).
operation SWAP(q1 : Qubit, q2 : Qubit) : Unit is Adj + Ctl {

    body (...) {
        CNOT(q1, q2);
        CNOT(q2, q1);
        CNOT(q1, q2);
    }

    adjoint (...) {
        SWAP(q1, q2);
    }

    controlled (cs, ...) {
        CNOT(q1, q2);
        Controlled CNOT(cs, (q2, q1));
        CNOT(q1, q2);
    }
}

/// The main function cannot be Adj or Ctl.
operation Main() : Unit {

    // We invoke specializations using functors at the call site.
    // In order to call these operations and their specializations, we need
    // to allocate some qubits.
    use (q1, q2) = (Qubit(), Qubit());

    // We can call `SWAP` in the normal way, without any functors or
    // specializations.
    SWAP(q1, q2);

    // We use the functor `Adjoint` on the operation `SWAP` to invoke the
    // adjoint specialization of `SWAP`.
    Adjoint SWAP(q1, q2);

    // Now,we will use the `Controlled` functor. To use this functor, we
    // need some control qubits.

    // The `Controlled` functor invokes the control specialization of the
    // operation. Note that the control specialization has a different
    // signature than the regular operation: first, the control qubits;
    // second, the parameters for the regular operation.
    // For a singly controlled invocation, only pass one control qubit
    // in the first array.
    use ctl = Qubit();
    Controlled SWAP([ctl], (q1, q2));

    // For a multi controlled invocation, pass an array of multiple qubits
    // in as the first argument.
    use ctls = Qubit[3];
    Controlled SWAP(ctls, (q1, q2));
}

/// # Sample
/// Superdense Coding
///
/// # Description
/// Superdense coding is a quantum communication protocol to communicate a
/// number of classical bits of information by only transmitting a smaller
/// number of qubits.
///
/// This Q# program implements superdense coding to send two classical bits of
/// information.
operation Main() : ((Bool, Bool), (Bool, Bool)) {
    use (aliceQubit, bobQubit) = (Qubit(), Qubit());

    // The protocol starts with the preparation of an entangled state, which
    // is later shared between Alice and Bob.
    CreateEntangledPair(aliceQubit, bobQubit);

    // Alice encodes 2 random bits in her qubit of the entangled pair.
    let sourceBit1 = DrawRandomBit();
    let sourceBit2 = DrawRandomBit();
    SuperdenseEncode(sourceBit1, sourceBit2, aliceQubit);

    // "Send" Alice's qubit to Bob and let Bob decode two bits.
    let (decodedBit1, decodedBit2) = SuperdenseDecode(aliceQubit, bobQubit);

    ResetAll([aliceQubit, bobQubit]);
    return ((sourceBit1, sourceBit2), (decodedBit1, decodedBit2));
}

// Generates random bit using an auxiliary qubit
operation DrawRandomBit() : Bool {
    use q = Qubit();
    H(q);
    return MResetZ(q) == One;
}

// Prepares an entangled state: 1/sqrt(2)(|00〉 + |11〉)
operation CreateEntangledPair(q1 : Qubit, q2 : Qubit) : Unit {
    H(q1);
    CNOT(q1, q2);
}

// Encodes two bits of information in one qubit. The qubit is expected to
// be a half of an entangled pair.
operation SuperdenseEncode(bit1 : Bool, bit2 : Bool, qubit : Qubit) : Unit {
    if (bit1) {
        Z(qubit);
    }
    if (bit2) {
        X(qubit);
    }
}

// Decodes two bits of information from a joint state of two qubits.
operation SuperdenseDecode(qubit1 : Qubit, qubit2 : Qubit) : (Bool, Bool) {
    // If bit1 in the encoding procedure was true we applied Z to the first
    // qubit which anti-commutes with XX, therefore bit1 can be read out
    // from XX measurement.
    let bit1 = Measure([PauliX, PauliX], [qubit1, qubit2]) == One;

    // If bit2 in the encoding procedure was true we applied X to the first
    // qubit which anti-commutes with ZZ, therefore bit2 can be read out
    // from ZZ measurement.
    let bit2 = Measure([PauliZ, PauliZ], [qubit1, qubit2]) == One;
    return (bit1, bit2);
}

/// # Summary
/// Simple Quantum Random Number Generator sample
///
/// # Description
/// This program implements a quantum random number generator by setting qubits
/// into superposition and then using the measurement results as random bits.
/// This is equivalent to generating a random number in the range of 0..2ᴺ-1.
operation Main() : Result[] {
    // Generate a 5-bit random number.
    GenerateNRandomBits(5)
}

/// # Summary
/// Generates N random bits in the form of `Zero` or `One` results.
operation GenerateNRandomBits(nBits : Int) : Result[] {
    // Array for the results
    mutable results = [];
    for _ in 1..nBits {
        // Append next random result to the array
        results += [GenerateRandomBit()];
    }
    results
}

/// # Summary
/// Generates a random bit in the form of `Zero` or `One` result.
operation GenerateRandomBit() : Result {
    // Allocate a qubit
    use q = Qubit();
    // Set the qubit into uniform superposition of |0〉 and |1〉
    H(q);
    // Now the qubit has 50% chance of being measured as `One`
    // and 50% chance of being measured as `Zero`.
    // Measure and reset the qubit. Return the result.
    MResetZ(q)
}

// # Sample
// Conditional Branching
//
// # Description
// Q# supports three branching keywords: `if`, `elif`, and `else`. These behave in the normal
// way, if you're familiar with if expressions or statements in other languages. One key distinction
// in Q# is that ifs are expressions, not statements. That means that they can return values, and
// they effectively perform the job of both ternary expressions and if statements in other languages.
// If expressions allow your code to branch, or conditionally execute parts of a Q# program.

function Main() : Unit {
    let number = 5;
    // Conditionally messages "Fizz" if the `number`, in this case 5, is divisible by 3.
    // Since 5 is not divisible by 3, the message "Fizz" will not be printed.
    if number % 3 == 0 { Message("Fizz"); }

    // Conditionally messages "Buzz" if the `number`, in this case 5, is divisible by 5.
    // Since 5 is divisible by 5, the message "Buzz" will be printed.
    if number % 5 == 0 { Message("Buzz"); }

    let fahrenheit = 40;

    // In this example, we print a message based on the temperature. The
    // message that will be printed is "It is livable".
    // `elif` allows you to express successive conditional expressions, with each
    // successive condition only being evaluated if the previous one was false.
    if fahrenheit <= 32 {
        Message("It's freezing");
    } elif fahrenheit <= 85 {
        Message("It is livable");
    } else {
        Message("It is way too hot");
    }
    let fahrenheit = -40;
    // `if` can also be used as an expression, to conditionally return a value.
    let absoluteValue = if fahrenheit > 0 { fahrenheit } else { fahrenheit * -1 };
    Message($"Absolute value of {fahrenheit} is {absoluteValue}");
}

